<template><div><table v-if="items.length"><thead><tr><th><input type="checkbox" :checked="allSelected" @change="toggleAll"></th><th>{{t('promptops.datasets.name')}}</th><th>{{t('promptops.datasets.variables')}}</th><th>{{t('promptops.datasets.validationRules')}}</th><th>{{t('promptops.datasets.tags')}}</th><th>{{t('promptops.datasets.updated')}}</th><th>{{t('promptops.datasets.actions')}}</th></tr></thead><tbody><tr v-for="item in items" :key="item.id"><td><input type="checkbox" :checked="selected.includes(item.id)" @change="$emit('toggle',item.id)"></td><td><strong>{{item.name}}</strong><small>{{item.description}}</small></td><td>{{Object.keys(item.variables).length}} · {{Object.keys(item.variables).slice(0,3).join(', ')}}</td><td>{{summary(item)}}</td><td>{{item.tags?.join(', ')||'—'}}</td><td>{{new Date(item.updatedAt).toLocaleString()}}</td><td><button :disabled="readonly" @click="$emit('edit',item)">{{t('promptops.actions.edit')}}</button><button :disabled="readonly" @click="$emit('duplicate',item)">{{t('promptops.datasets.duplicate')}}</button><button class="danger" :disabled="readonly" @click="$emit('delete',item)">{{t('promptops.datasets.deleteCase')}}</button></td></tr></tbody></table><p v-else class="empty">{{t('promptops.datasets.noCases')}}</p></div></template>
<script setup lang="ts">import{computed}from'vue';import{useI18n}from'vue-i18n';import type{DatasetTestCase}from'@prompt-optimizer/core';const props=defineProps<{items:DatasetTestCase[];selected:string[];readonly:boolean}>();const emit=defineEmits<{toggle:[string];toggleAll:[boolean];edit:[DatasetTestCase];duplicate:[DatasetTestCase];delete:[DatasetTestCase]}>();const{t}=useI18n();const allSelected=computed(()=>props.items.length>0&&props.items.every(x=>props.selected.includes(x.id)));const toggleAll=(event:Event)=>emit('toggleAll',(event.target as HTMLInputElement).checked);const summary=(item:DatasetTestCase)=>[item.expectedValidation?.type,item.expectedValidation?.contains?.length?`+${item.expectedValidation.contains.length}`:'',item.expectedValidation?.notContains?.length?`-${item.expectedValidation.notContains.length}`:''].filter(Boolean).join(' ')||'—'</script>
<style scoped>table{width:100%;border-collapse:collapse;background:var(--n-color,#fff)}th,td{text-align:left;padding:11px;border-bottom:1px solid #e5e7eb;vertical-align:top}td:first-child,th:first-child{width:35px}small{display:block;color:#64748b;margin-top:3px}button{margin:2px;padding:5px 8px}.danger{color:#b91c1c}.empty{text-align:center;padding:44px;color:#64748b}</style>
